customCSS:
/* Black Ice - Sharp and Clean */
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@300;400;500;600&family=Fira+Code&display=swap');

.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 30% 0%, rgba(107, 184, 255, 0.20), transparent),
    radial-gradient(ellipse 500px 350px at 70% 100%, rgba(128, 229, 229, 0.14), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(107, 184, 255, 0.12);
  backdrop-filter: blur(10px);
}

.stat-card::before {
  background: linear-gradient(90deg, #6bb8ff, #80e5e5);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(128, 229, 229, 0.25);
  box-shadow: 0 4px 30px rgba(107, 184, 255, 0.12);
}

.stat-value {
  text-shadow: 0 0 20px rgba(107, 184, 255, 0.5);
}

.celebration-title {
  background: linear-gradient(135deg, #6bb8ff, #80e5e5);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
  filter: drop-shadow(0 0 20px rgba(107, 184, 255, 0.4));
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(107, 184, 255, 0.08);
}

.miner-card:hover {
  border-color: rgba(128, 229, 229, 0.2);
}

.logo {
  color: #6bb8ff;
}
